pub fn print_colorful_warning(
    command: &str,
    reason: &str,
    pack: Option<&str>,
    pattern: Option<&str>,
    explanation: Option<&str>,
    allow_once_code: Option<&str>,
    matched_span: Option<&MatchSpan>,
    pattern_suggestions: &[PatternSuggestion],
) {
    #[cfg(feature = "rich-output")]
    {
        use crate::output::{console, DenialBox};
        use crate::output::theme::Severity;

        // Determine severity from pack/pattern (heuristic)
        let severity = determine_severity_from_pack(pack);

        // Build DenialBox
        let denial = DenialBox {
            command: command.to_string(),
            reason: reason.to_string(),
            pack: pack.map(String::from),
            pattern: pattern.map(String::from),
            explanation: explanation.map(String::from),
            severity: Some(severity),
            allow_once_code: allow_once_code.map(String::from),
            matched_span: matched_span.cloned(),
        };

        // Render to stderr via console
        let theme = crate::output::auto_theme();
        eprintln!("{}", denial.render(&theme));

        // Render suggestions panel if present
        if !pattern_suggestions.is_empty() {
            eprintln!("{}", render_suggestions_panel(pattern_suggestions, &theme));
        }

        return;
    }

    // Legacy implementation (no rich-output feature)
    #[cfg(not(feature = "rich-output"))]
    {
        // ... keep existing colored-based implementation
    }
}

fn determine_severity_from_pack(pack: Option<&str>) -> Severity {
    // Heuristic based on pack name patterns
    match pack {
        Some(p) if p.contains("critical") => Severity::Critical,
        Some(p) if p.contains("filesystem") && p.contains("root") => Severity::Critical,
        Some(p) if p.contains("database") && p.contains("drop") => Severity::Critical,
        Some(p) if p.contains("git") => Severity::High,
        Some(p) if p.contains("kubernetes") && p.contains("delete") => Severity::High,
        _ => Severity::Medium,
    }
}
```

### CRITICAL: Agent Safety

This function prints to STDERR. The JSON verdict goes to STDOUT separately. This separation is ESSENTIAL for agent compatibility.

